class BankAccount {
    private double balance;

    public BankAccount(double initial) {
        balance = initial;
    }

    public void deposit(double amount) {
        if (amount > 0) {
            balance += amount;
        }
    }

    public double getBalance() {
        return balance;
    }
}

BankAccount acc = new BankAccount(1000);
acc.deposit(-500);
System.out.println(acc.getBalance());
